	static long solve(long a,long b)
	{
		if(a<=0 || b<=0)
		{
			return 0;
		}
		else
		{
			long max=Math.max(a,b),min=Math.min(a,b);
			long low=1,high=(long)(1e9);
			while(low<high)
			{
