			int x = in.nextInt()-1;
			int y = in.nextInt()-1;
			q.add(x);
			q.add(y);
			q.add(0);
			seen[x][y] = 0;
		}
		while(!q.isEmpty()) {
			int x = q.poll();
			int y = q.poll();
			int t = q.poll();
			for(int i=0; i<dx.length; i++) {
				int nx = x + dx[i];
				int ny = y + dy[i];
				if(nx < 0 || nx >= n || ny < 0 || ny >= m)
					continue;
				if(seen[nx][ny] != -1) continue;
				seen[nx][ny] = t+1;
				q.add(nx);
				q.add(ny);
				q.add(t+1);
			}
