	static long MOD=1000000007;
	public static long pow(long x,long k){
		long base=x%MOD;
		long res=1;
		while(k>0){
			if((k&1)==1){
				res=(res*base)%MOD;
			}
			base=(base*base)%MOD;
			k>>=1;
		}
		return res;
	}

	public static void main (String[] args) throws java.lang.Exception
	{
		Scanner scan=new Scanner(System.in);
