		if(x==0){System.out.println(0);return;}
		x %= MOD;
		long a=pow(2L,k+1);
		long b=pow(2L,k);
		long res=(a*x)%MOD-b+1;
		if(res<0){res+=MOD;}
		System.out.println(res%MOD);
	}
