		HashMap<Long,ArrayList<Node>> map=new HashMap<>();

		long sum;
		for(int i=0;i<n;i++){
			sum=0;
			for(int j=i;j<n;j++){
				sum+=a[j];
				if(!map.containsKey(sum))
					map.put(sum,new ArrayList<>());
				map.get(sum).add( new Node(i+1, j+1) );
