        for (int i=0; i<n; ++i)
            for (int j=0; j<n; ++j)
                pb[i][j] = sc.nextDouble();

        int m = (1<<n);
        double[] dp = new double[m];
        dp[0] = 1.0f;
        for (int i=1; i<m; ++i)
            for (int j=0; j<n; ++j) if ((i & (1<<j)) != 0)
                for (int k=0; k<n; ++k) if ((i & (1<<k)) == 0)
                    dp[i] += pb[k][j] * dp[i & ~(1<<j)] / c(n - Integer.bitCount(i) + 1);

