public class Solution implements Runnable {

	public long gcd(long a, long b) {
		long tmp;
		while (b > 0) {
			a %= b;
			tmp = a;
			a = b;
			b = tmp;
		}
		return a;
	}

	public void solve() throws Exception {
		long a = sc.nextLong();
		long b = sc.nextLong();
		long ans = 0;
		long k = 0;
		if (a == 1 || b == 1) {
			out.println(max(a, b));
			return;
		}
		while (a > 1 && b > 1) {
			if (a > b) {
				k = a / b;
				ans += k;
				a -= (k * b);				
			} else {
				k = b / a;
				ans += k;
				b -= (k * a);
			}
			k = gcd(a, b);
			a /= k;
			b /= k;
		}
		if (a == 1)
			ans += b;
		else
			ans += a;
		out.println(ans);
	}

