		long n = in.nextLong() - 1;
		long k = in.nextLong() - 1;
		if (n == 0) {
			out.print("0");
		} else {
			if (k >= n) {
				out.print("1");
			} else {
				if (k * (k + 1) / 2 < n) {
					out.print("-1");
				} else {
					long t = binsearch(n, k, 1, k);
					long ans = k - t + 1;
