						ans++;
					System.out.println(ans);
				}
			}
		}
	}

	public static long binsearch(long n, long k, long from, long to) {
		if (from == to) {
			return from;
		}
		long mid = (from + to) / 2;
		if ((k * (k + 1)) / 2 - (mid * (mid - 1)) / 2 > n)
			return binsearch(n, k, mid + 1, to);
		else

			return binsearch(n, k, from, mid);
	}
}

