			ans[i] = a[j][col];
		}
		return ans;

	}

	static int dp(int col, int msk) {
		if (col == n||col==m)
			return 0;
		if (memo[msk][col] != -1)
			return memo[msk][col];
		int ans = 0;
		for (int shift = 0; shift < n; shift++) {
			int[] currCol = getCol(indices[col], shift);
			for (int nxtMsk = 0; nxtMsk < 1 << n; nxtMsk++) {
				if ((nxtMsk & msk) != msk)
					continue;
				int curr = 0;
				int diff = msk ^ nxtMsk;
				for (int i = 0; i < n; i++)
					if ((diff & 1 << i) != 0)
						curr += currCol[i];
				ans = Math.max(ans, dp(col + 1, nxtMsk) + curr);
			}
		}
		return memo[msk][col] = ans;
	}

