            r = r * 26 + (s.charAt(i) - 'A' + 1);
        }
        return r;
    }

    String i2s(int i) {
        StringBuffer s = new StringBuffer();
        while (i > 0) {
            i -= 1;
            s.append((char)('A' + (i % 26)));
            i /= 26;
        }
        return s.reverse().toString();
    }

