        for (int i = 0; i < n; i++) {
            dp[1 << i][i] = 1;
        }
        for (int mask = 0; mask < (1 << n); mask++) {
            if (Integer.bitCount(mask) > 1) {
                for (int i = 0; i < n; i++) {
                    if (i==Integer.numberOfTrailingZeros(mask))
                        continue;
                    if ((mask & (1 << i)) != 0) {
                        for (int j = 0; j < n; j++) {
                            if ((mask & (1 << j)) != 0 && a[j][i]==1) {
                                dp[mask][i] += dp[(mask ^ (1 << i))][j];
                            }
                        }
                    }
                }
            }
        }
        long ans = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            if (Integer.bitCount(mask) >= 3) {
