        in.nextLine();

        int pre = 0;
        int size = 0;

        int[] block = new int[MAX];
        for (int i = 0; i < n; i++) {
            String command = in.nextLine();
            if (command.startsWith("s")) {
                block[size++] = pre;
                pre = 0;
            } else {
                pre++;
            }
        }

        if (pre != 0) {
            System.out.println(0);
