            int currentIndex = preIndex ^ 1;
            int j = block[i - 1];
            for (int k = currentMax; k >= 0; k--) {
                result[currentIndex][k + j] = (result[currentIndex][k + j + 1] + result[preIndex][k]) % MODULO;
            }
            for (int k = j - 1; k >= 0; k--) {
                result[currentIndex][k] = result[currentIndex][j];

            }
            currentMax += j;
