        c[1]++;

        for (int i = 1; i < n; i++) {
            if (a[i].pr == a[i - 1].pr && a[i].time == a[i - 1].time)
                for (int j = i + 1; j >= prev; j--)
                    c[j] = i + 2 - prev;
            else {
                prev = i + 1;
                c[prev] = 1;
            }
        }

        out.println(c[k]);
        out.close();
    }
