static long count(int at, int start, int mask)
{
	if(memo[at][mask] != -1) return memo[at][mask];
	int bits = Integer.bitCount(mask);
	if(at == start && bits > 2) return 1;
	long res = 0;
	for(int i = 0; i<=start; i++)
	{
