				throws NumberFormatException, IOException {
			PrintWriter pw = new PrintWriter(os);
			Scanner sc = new Scanner(is);

			long a = sc.nextLong();
			long b = sc.nextLong();

			pw.println(r(a, b));

			pw.flush();
			sc.close();
		}
	}

