class Solver {

	private long n, s;

	Solver(long n, long s) {
		this.n = n;
		this.s = s;
	}

	public long solve() {
		long low = 1, high = n;
		for (int i = 0; i < 72; ++i) {
			long x = low + (high - low) / 2;
			if (check(x))
				high = x - 1;
			else
				low = x + 1;
		}
		return n - high;
	}

	private boolean check(long x) {

		long tmp = x;
		int sum = 0;
		while (tmp > 0) {
			sum += tmp % 10;
			tmp /= 10;
		}
		return x - sum >= s;
	}
}

