class Task {
    int n;
    int[] a;
    int[] b;

    public void solve(int testNumber, InputReader in, PrintWriter out) {
        n = in.readInt();
        a = new int[n];
        b = new int[n];
        for (int i = 0; i < n; ++i)
            a[i] = b[i] = in.readInt();
        sort(0, n - 1);
        int different = 0;
        for (int i = 0; i < n; ++i)
            if (a[i] != b[i])
                ++different;
        out.println(different <= 2 ? "YES" : "NO");
    }

    public void sort(int lo, int hi) {
        if (lo < hi) {
            int mid = (lo + hi) / 2;
            sort(lo, mid);
            sort(mid + 1, hi);
            merge(lo, mid, hi);
        }
    }

    public void merge(int lo, int mid, int hi) {
        int n1 = mid - lo + 1;
        int n2 = hi - (mid + 1) + 1;
        int[] x = new int[n1 + 1];
        int[] y = new int[n2 + 1];
        for (int i = 0; i < n1; ++i)
            x[i] = b[lo + i];
        for (int j = 0; j < n2; ++j)
            y[j] = b[mid + 1 + j];
        x[n1] = y[n2] = Integer.MAX_VALUE;
        for (int k = lo, i = 0, j = 0; k <= hi; ++k)
            b[k] = x[i] < y[j] ? x[i++] : y[j++];
    }
}

